class Solution {
public:
    int minCut(string s) {
        int n = s.size();
        vector<vector<bool>> pal(n, vector<bool>(n));
        for (int i = n - 1; i >= 0; i--)
            for (int j = i; j < n; j++)
                pal[i][j] = s[i] == s[j] && (j - i < 2 || pal[i+1][j-1]);
        vector<int> dp(n);
        for (int j = 0; j < n; j++) {
            if (pal[0][j]) dp[j] = 0;
            else {
                dp[j] = j;
                for (int i = 1; i <= j; i++)
                    if (pal[i][j]) dp[j] = min(dp[j], dp[i-1] + 1);
            }
        }
        return dp[n-1];
    }
};
